type LoggerCallback interface {
	Level() (int32, error)
	Log(message string) error
}

type LoggerCallbackDefaults struct{}

func (LoggerCallbackDefaults) Level() (int32, error)    { return 0, nil }
func (LoggerCallbackDefaults) Log(message string) error { return nil }

type loggerCallbackAdapter struct {
	impl LoggerCallback
}

func (a *loggerCallbackAdapter) HandleCallback(methodID int32, req []byte) ([]byte, error) {
	switch methodID {
	case 0: // Level
		_v, err := a.impl.Level()
		if err != nil {
			return nil, err
		}
		var _out []byte
		_out = pbAppendInt32(_out, 1, _v)
		return _out, nil
	case 1: // Log
		var message string
		_r := &pbReader{data: req}
		for _f, _w, _ok := _r.next(); _ok; _f, _w, _ok = _r.next() {
			switch _f {
			case 1:
				message = _r.readString()
			default:
				_r.skip(_w)
			}
		}
		err := a.impl.Log(message)
		if err != nil {
			return nil, err
		}
		return nil, nil
	}
	return nil, fmt.Errorf("unknown callback method %d", methodID)
}

