// Abstract interface that users can implement from Go. The bridge emits a
// trampoline that dispatches each pure-virtual through the callback wire
// (wasmify_callback_invoke) so a Go type can satisfy the C++ vtable.
type Logger struct {
	ptr       uint64
	keepAlive []any
}

func (h *Logger) rawPtr() uint64 { return h.ptr }

func (h *Logger) setKeepAlive(v any) {
	if h != nil && v != nil {
		h.keepAlive = append(h.keepAlive, v)
	}
}

func (*Logger) isLogger() {}

func newLogger(ptr uint64) *Logger {
	h := &Logger{ptr: ptr}
	runtime.SetFinalizer(h, (*Logger).free)
	return h
}

func newLoggerNoFinalizer(ptr uint64) *Logger {
	h := &Logger{ptr: ptr}
	return h
}

func (h *Logger) Level() (int32, error) {
	var buf []byte
	buf = pbAppendHandle(buf, 1, h.ptr)
	resp, err := module().invoke(7, 0, buf)
	if err != nil {
		return 0, err
	}
	if e := pbExtractError(resp); e != nil {
		return 0, e
	}
	var result int32
	pr := &pbReader{data: resp}
	for f, w, ok := pr.next(); ok; f, w, ok = pr.next() {
		if f == 1 {
			result = pr.readInt32()
		} else {
			pr.skip(w)
		}
	}
	return result, nil
}

