// TextNode / HeadingNode regression-test the abstract-handle naming
// rule. TextNode itself ends in "Node", so the generator must emit the
// Go interface as `TextNode` (not the doubled `TextNodeNode`) and
// rename the abstract struct to `TextNodeBase` so it does not collide
// with the interface. HeadingNode is a concrete descendant whose struct
// embeds `*TextNodeBase`.
type TextNodeBase struct {
	ptr       uint64
	keepAlive []any
}

func (h *TextNodeBase) rawPtr() uint64 { return h.ptr }

func (h *TextNodeBase) setKeepAlive(v any) {
	if h != nil && v != nil {
		h.keepAlive = append(h.keepAlive, v)
	}
}

func (*TextNodeBase) isTextNode() {}

func newTextNodeBase(ptr uint64) *TextNodeBase {
	h := &TextNodeBase{ptr: ptr}
	runtime.SetFinalizer(h, (*TextNodeBase).free)
	return h
}

func newTextNodeBaseNoFinalizer(ptr uint64) *TextNodeBase {
	h := &TextNodeBase{ptr: ptr}
	return h
}

func (h *TextNodeBase) Render() (string, error) {
	var buf []byte
	buf = pbAppendHandle(buf, 1, h.ptr)
	resp, err := module().invoke(19, 0, buf)
	if err != nil {
		return "", err
	}
	if e := pbExtractError(resp); e != nil {
		return "", e
	}
	var result string
	pr := &pbReader{data: resp}
	for f, w, ok := pr.next(); ok; f, w, ok = pr.next() {
		if f == 1 {
			result = pr.readString()
		} else {
			pr.skip(w)
		}
	}
	return result, nil
}

func NewTextNodeFromImpl(impl TextNodeCallback) (*TextNodeBase, error) {
	adapter := &textNodeCallbackAdapter{impl: impl}
	id := RegisterCallback(adapter)
	var buf []byte
	buf = pbAppendInt32(buf, 1, id)
	resp, err := module().invoke(19, 1, buf)
	if err != nil {
		UnregisterCallback(id)
		return nil, err
	}
	if e := pbExtractError(resp); e != nil {
		UnregisterCallback(id)
		return nil, e
	}
	var ptr uint64
	_pbr := &pbReader{data: resp}
	for f, w, ok := _pbr.next(); ok; f, w, ok = _pbr.next() {
		if f == 1 {
			ptr = _pbr.readUint64()
		} else {
			_pbr.skip(w)
		}
	}
	h := newTextNodeBase(ptr)
	runtime.SetFinalizer(h, nil)
	runtime.SetFinalizer(h, func(h *TextNodeBase) { h.free(); UnregisterCallback(id) })
	return h, nil
}

func (h *TextNodeBase) free() {
	if h.ptr != 0 {
		buf := pbAppendHandle(nil, 1, h.ptr)
		module().invoke(19, 2, buf)
		h.ptr = 0
	}
}

